        example:
          'import os\nfrom whop_sdk import Whop\n\nclient = Whop(\n    api_key=os.environ.get("WHOP_API_KEY"),  # This is the default and can be omitted\n)\nmembership = client.memberships.resync_access(\n    "mem_xxxxxxxxxxxxxx",\n)\nprint(membership.id)',
